import { test, expect } from '@playwright/test';

test("Arabic and mixed-script names are rejected", async ({ page }) => {
  await page.goto("https://arabic-market-blocker-agent.onrender.com/demo/adaptive/");
  const field = page.getByLabel("How should we greet you?");
  await field.fill("عبد الرحمن بن خالد العتيبي");
  await field.blur();
  await expect(field).toHaveValue("عبد الرحمن بن خالد العتيبي");
  await expect(page.getByText("Only Latin letters are allowed", { exact: false })).not.toBeVisible();
});

import { test, expect } from '@playwright/test';

test("Saudi phone formats are rejected", async ({ page }) => {
  await page.goto("https://arabic-market-blocker-agent.onrender.com/demo/adaptive/");
  const field = page.getByLabel("Mobile / WhatsApp");
  await field.fill("0551234567");
  await field.blur();
  await expect(field).toHaveValue("0551234567");
  await expect(page.getByText("Use an accepted US contact number", { exact: false })).not.toBeVisible();
});
